customCss:
/*
  Silo Porsche Design System v4 Theme
*/

:root,
.dark {
  color-scheme: dark;

  /* Porsche Design System v4 color layer */
  --p-color-focus: #1A44EA;
  --p-color-canvas: hsl(225 66.7% 1.2%);
  --p-color-surface: hsl(240 2% 10%);
  --p-color-frosted: hsl(240 2% 43% / 0.228);
  --p-color-frosted-soft: hsl(240 3.7% 26.5% / 0.154);
  --p-color-frosted-strong: hsl(240 1.5% 61.8% / 0.302);
  --p-color-backdrop: hsl(240 5.3% 14.9% / 0.5);

  --p-color-primary: hsl(225 100% 99%);
  --p-color-contrast-higher: hsl(240 12.5% 96.9% / 0.78);
  --p-color-contrast-high: hsl(240 12.5% 96.9% / 0.67);
  --p-color-contrast-medium: hsl(240 12.5% 96.9% / 0.56);
  --p-color-contrast-low: hsl(240 12.5% 96.9% / 0.45);
  --p-color-contrast-lower: hsl(240 1.5% 61.8% / 0.302);

  --p-color-info: hsl(210 100% 54.5%);
  --p-color-info-medium: hsl(210 100% 54.5% / 0.6);
  --p-color-info-low: hsl(210 100% 54.5% / 0.18);
  --p-color-info-frosted: hsl(210 79% 20% / 0.66);
  --p-color-info-frosted-soft: hsl(210 59% 15% / 0.66);

  --p-color-success: hsl(157 84.9% 41.6%);
  --p-color-warning: hsl(28 90.2% 56.1%);
  --p-color-error: hsl(0 96.9% 62%);

  /* Porsche Design System v4 typography/spacing/radius/motion layer */
  --p-font-porsche-next: "Porsche Next", "Arial Narrow", Arial, "Heiti SC", SimHei, sans-serif;
  --p-font-weight-normal: 400;
  --p-font-weight-semibold: 600;
  --p-font-weight-bold: 700;
  --p-leading-normal: calc(6px + 2.125ex);

  --p-spacing-fluid-xs: clamp(4px, 0.25vw + 3px, 8px);
  --p-spacing-fluid-sm: clamp(8px, 0.5vw + 6px, 16px);
  --p-spacing-fluid-md: clamp(16px, 1.25vw + 12px, 36px);
  --p-spacing-fluid-lg: clamp(32px, 2.75vw + 23px, 76px);
  --p-spacing-static-xs: 4px;
  --p-spacing-static-sm: 8px;
  --p-spacing-static-md: 16px;
  --p-spacing-static-lg: 32px;

  --p-radius-xs: 2px;
  --p-radius-sm: 4px;
  --p-radius-md: 6px;
  --p-radius-lg: 8px;
  --p-radius-xl: 12px;
  --p-radius-full: 9999px;

  --p-blur-frosted: blur(32px);
  --p-shadow-sm: 0px 3px 8px rgba(0, 0, 0, .16);
  --p-shadow-md: 0px 4px 16px rgba(0, 0, 0, .16);
  --p-shadow-lg: 0px 8px 40px rgba(0, 0, 0, .16);

  --p-duration-sm: .25s;
  --p-duration-md: .4s;
  --p-ease-out: cubic-bezier(.4, 0, .5, 1);
}

html,
body {
  background: var(--p-color-canvas);
  color: var(--p-color-primary);
  font-family: var(--p-font-porsche-next);
  line-height: var(--p-leading-normal);
  text-rendering: optimizeLegibility;
}

/*
  Striping fix:
  Silo uses bg-muted/bg-secondary/surface-style bars for some card headers.
  These are flattened only when they are direct card header/section children,
  so nested stat cards and normal controls keep their own surfaces.
*/
.bg-card > :first-child,
.bg-card > header:first-child,
.bg-card > [class*="border-b"]:first-child,
.bg-card > [class*="bg-muted"]:first-child,
.bg-card > [class*="bg-secondary"]:first-child,
.bg-card > [class*="bg-surface"]:first-child {
  background: transparent !important;
  background-image: none !important;
}

/* Keep frosted glass on actual card/popover surfaces without repainting every region. */
.bg-card,
.bg-popover {
  backdrop-filter: var(--p-blur-frosted);
  -webkit-backdrop-filter: var(--p-blur-frosted);
  box-shadow: var(--p-shadow-sm);
}

/* Card hover remains Porsche graphite/frosted, not blue. */
.bg-card:hover {
  border-color: var(--p-color-contrast-low);
  box-shadow: var(--p-shadow-md);
}

/* Open/selected/expanded states get restrained Porsche focus treatment only. */
.bg-card[data-state="open"],
.bg-card[aria-expanded="true"],
.bg-card[data-selected="true"],
.bg-card[data-active="true"],
.bg-card.is-active {
  background:
    linear-gradient(180deg, var(--p-color-info-low), transparent 68%),
    hsl(240 2% 10% / 0.88) !important;
  border-color: var(--p-color-focus) !important;
  box-shadow:
    0 0 0 1px color-mix(in srgb, var(--p-color-focus) 55%, transparent),
    var(--p-shadow-md);
}

/* Porsche focus blue only for real focus states. */
:focus-visible {
  outline: 2px solid var(--p-color-focus) !important;
  outline-offset: 2px;
}

/* Inputs */
input,
select,
textarea {
  font-family: var(--p-font-porsche-next);
  background: hsl(240 2% 43% / 0.228);
  border-color: var(--p-color-contrast-lower);
  color: var(--p-color-primary);
  backdrop-filter: var(--p-blur-frosted);
  -webkit-backdrop-filter: var(--p-blur-frosted);
}

input:focus,
select:focus,
textarea:focus {
  border-color: var(--p-color-focus);
  box-shadow: 0 0 0 1px var(--p-color-focus);
}

/* Buttons and links */
button,
[role="button"],
a {
  font-family: var(--p-font-porsche-next);
}

button,
[role="button"] {
  border-radius: var(--p-radius-md);
  transition:
    background var(--p-duration-sm) var(--p-ease-out),
    border-color var(--p-duration-sm) var(--p-ease-out),
    color var(--p-duration-sm) var(--p-ease-out),
    transform var(--p-duration-sm) var(--p-ease-out);
}

button:hover,
[role="button"]:hover {
  transform: translateY(-1px);
}

/* Popovers/dialogs */
[role="dialog"],
[role="menu"],
[data-radix-popper-content-wrapper] > * {
  background: hsl(240 2% 10% / 0.96);
  border-color: var(--p-color-contrast-lower);
  box-shadow: var(--p-shadow-lg);
  backdrop-filter: var(--p-blur-frosted);
  -webkit-backdrop-filter: var(--p-blur-frosted);
}

/*
  Sidebar/nav safety:
  Do not repaint all aside/nav/sidebar elements black.
  Let Silo's sidebar tokens control the base surface instead.
*/
aside,
nav,
[data-sidebar],
[class*="sidebar"] {
  background-color: unset;
}

[data-sidebar],
[class*="sidebar"] {
  background: hsl(240 2% 10% / 0.72);
  border-color: var(--p-color-contrast-lower);
  backdrop-filter: var(--p-blur-frosted);
  -webkit-backdrop-filter: var(--p-blur-frosted);
}

[data-sidebar] a,
[class*="sidebar"] a {
  border-radius: var(--p-radius-md);
}

[data-sidebar] a:hover,
[class*="sidebar"] a:hover {
  background: var(--p-color-frosted-soft);
}

/* Porsche squared marquee tabs */
.marquee-tab-bar {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 2px;
  border-radius: var(--p-radius-sm) !important;
  background:
    linear-gradient(180deg, hsl(240 2% 43% / 0.12), transparent),
    var(--p-color-frosted-soft) !important;
  border: 1px solid var(--p-color-contrast-lower);
  box-shadow: var(--p-shadow-sm);
  backdrop-filter: var(--p-blur-frosted);
  -webkit-backdrop-filter: var(--p-blur-frosted);
}

.marquee-tab-trigger {
  position: relative;
  min-height: 34px;
  padding: 0 14px;
  border-radius: var(--p-radius-xs) !important;
  border: 1px solid transparent;
  background: transparent !important;
  color: var(--p-color-contrast-high);
  font-family: var(--p-font-porsche-next);
  font-weight: var(--p-font-weight-semibold);
  line-height: 1;
  box-shadow: none !important;
  transform: none !important;
  transition:
    background var(--p-duration-sm) var(--p-ease-out),
    border-color var(--p-duration-sm) var(--p-ease-out),
    color var(--p-duration-sm) var(--p-ease-out);
}

.marquee-tab-trigger:hover {
  background: var(--p-color-frosted-soft) !important;
  border-color: var(--p-color-contrast-lower);
  color: var(--p-color-primary);
  transform: none !important;
}

.marquee-tab-trigger[data-state="active"],
.marquee-tab-trigger[aria-selected="true"] {
  border-radius: var(--p-radius-xs) !important;
  background:
    linear-gradient(180deg, hsl(240 2% 43% / 0.18), hsl(240 2% 10% / 0.26)),
    var(--p-color-frosted) !important;
  border-color: var(--p-color-contrast-low);
  color: var(--p-color-primary);
  box-shadow:
    inset 0 -2px 0 var(--p-color-focus),
    0 0 0 1px hsl(240 1.5% 61.8% / 0.12) !important;
}

.marquee-tab-trigger[data-state="active"]::after,
.marquee-tab-trigger[aria-selected="true"]::after {
  content: "";
  position: absolute;
  left: 8px;
  right: 8px;
  bottom: 3px;
  height: 1px;
  background: color-mix(in srgb, var(--p-color-focus) 72%, transparent);
  pointer-events: none;
}

.marquee-tab-trigger:focus-visible {
  outline: 2px solid var(--p-color-focus) !important;
  outline-offset: 2px;
}
/* End Porsche squared marquee tabs */

/* Scrollbar finish */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--p-color-contrast-low) transparent;
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--p-color-contrast-low);
  border: 3px solid transparent;
  border-radius: var(--p-radius-full);
  background-clip: padding-box;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--p-color-contrast-medium);
  border: 3px solid transparent;
  background-clip: padding-box;
}
